function accordion(){const e=document.querySelectorAll(".questions__item");e.forEach((t=>{const s=t.querySelector(".questions__item-button"),i=t.querySelector(".questions__item-title"),o=t.querySelector(".questions__item-content");t.addEventListener("click",(()=>{const r=t.classList.contains("questions__item--open");e.forEach((e=>{e.classList.remove("questions__item--open"),e.querySelector(".questions__item-button").classList.remove("questions__item-button--open"),e.querySelector(".questions__item-title").classList.remove("questions__item-title--open"),e.querySelector(".questions__item-content").classList.remove("questions__item-content--open")})),r||(t.classList.add("questions__item--open"),s.classList.add("questions__item-button--open"),i.classList.add("questions__item-title--open"),o.classList.add("questions__item-content--open"))}))}))}accordion();const swiper=new Swiper(".reviews__swiper",{loop:!0,slidesPerView:3,spaceBetween:50,speed:500,navigation:{prevEl:".swiper-button-prev",nextEl:".swiper-button-next"}}),newSwiper=new Swiper(".awards__swiper",{loop:!0,slidesPerView:3,spaceBetween:40,speed:500,navigation:{prevEl:".awards__prev",nextEl:".awards__next"}}),buttons=document.querySelectorAll(".gallery__block-bottom-button"),boxes=document.querySelectorAll(".gallery__block-bottom-box");buttons.forEach((e=>{e.addEventListener("click",(()=>{const t=e.dataset.gallery;buttons.forEach((t=>t.classList.toggle("gallery__block-bottom-button-active",t===e))),boxes.forEach((e=>{e.classList.toggle("hide","all"!==t&&e.dataset.gallery!==t)}))}))}));const classroomSwiper=new Swiper(".swiper-classroom",{loop:!0,slidesPerView:4,spaceBetween:40,speed:500,navigation:{prevEl:".swiper-classroom-prev",nextEl:".swiper-classroom-next"}}),librarySwiper=new Swiper(".swiper-library",{loop:!0,slidesPerView:4,spaceBetween:40,speed:500,navigation:{prevEl:".swiper-library-prev",nextEl:".swiper-library-next"}}),scienceSwiper=new Swiper(".swiper-science",{loop:!0,slidesPerView:4,spaceBetween:40,speed:500,navigation:{prevEl:".swiper-science-prev",nextEl:".swiper-science-next"}}),computerSwiper=new Swiper(".swiper-computer",{loop:!0,slidesPerView:4,spaceBetween:40,speed:500,navigation:{prevEl:".swiper-computer-prev",nextEl:".swiper-computer-next"}}),areaSwiper=new Swiper(".swiper-area",{loop:!0,slidesPerView:4,spaceBetween:40,speed:500,navigation:{prevEl:".swiper-area-prev",nextEl:".swiper-area-next"}});